def process_graph(graph_data):
    graph_copy = graph_data.copy()

    # Add new node if it doesn't exist
    new_node_name = 'new_EK_PORT_24'
    if not any(node[1]['name'] == new_node_name for node in graph_copy.nodes(data=True)):
        graph_copy.add_node(new_node_name, type=['EK_PORT'], physical_capacity_bps=0)
        parent_name = 'ju1.a4.dom'
        graph_copy.add_edge(parent_name, new_node_name, type='RK_CONTAINS')

    # Get hierarchy under ju1.a4.dom
    parent_name = 'ju1.a4.dom'
    child_nodes = []

    def get_capacity(node):
        if 'EK_PORT' in graph_copy.nodes[node]['type']:
            return graph_copy.nodes[node].get('physical_capacity_bps', 0)
        total = 0
        for successor in graph_copy.successors(node):
            total += get_capacity(successor)
        return total

    # Process all direct children of ju1.a4.dom
    for successor in graph_copy.successors(parent_name):
        capacity = get_capacity(successor)
        child_nodes.append((successor, capacity))

    # Sort by capacity (descending)
    child_nodes_sorted = sorted(child_nodes, key=lambda x: x[1], reverse=True)

    return_object = {
        'type': 'list',
        'data': child_nodes_sorted,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

    return return_object

