def process_graph(graph_data):
    graph_copy = graph_data.copy()

    # Add the new node
    new_node_name = 'new_EK_PACKET_SWITCH_49'
    graph_copy.add_node(new_node_name, name=new_node_name, type=['EK_PACKET_SWITCH'])

    # Find the parent node ju1.a2.m2 (assuming it's a SUPERBLOCK or AGG_BLOCK)
    parent_node = None
    for node in graph_copy.nodes(data=True):
        if node[1]['name'] == 'ju1.a2.m2' and ('EK_SUPERBLOCK' in node[1]['type'] or 'EK_AGG_BLOCK' in node[1]['type']):
            parent_node = node[0]
            break

    if parent_node:
        graph_copy.add_edge(parent_node, new_node_name, type='RK_CONTAINS')

    # Get all direct children of ju1.a2.m2 and calculate their capacities
    children = []
    for successor in graph_copy.successors(parent_node):
        if 'RK_CONTAINS' in graph_copy.get_edge_data(parent_node, successor)['type']:
            # Calculate total capacity for the child
            total_capacity = 0
            # Get all ports under this child
            ports = []
            nodes_to_process = [successor]
            while nodes_to_process:
                current_node = nodes_to_process.pop()
                if 'EK_PORT' in graph_copy.nodes[current_node]['type']:
                    ports.append(current_node)
                for node_successor in graph_copy.successors(current_node):
                    if 'RK_CONTAINS' in graph_copy.get_edge_data(current_node, node_successor)['type']:
                        nodes_to_process.append(node_successor)
            for port in ports:
                if 'physical_capacity_bps' in graph_copy.nodes[port]:
                    total_capacity += graph_copy.nodes[port]['physical_capacity_bps']
            children.append((graph_copy.nodes[successor]['name'], total_capacity))

    # Sort children by capacity in descending order
    sorted_children = sorted(children, key=lambda x: x[1], reverse=True)

    return_object = {
        'type': 'list',
        'data': sorted_children,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }
    return return_object

